var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"제길! 대체 저 괴상한 로봇은 뭔데 끝도 없이 일어서는 거야?","JPN":"くそ！　あの妙なロボットはおきあがりこぼしか？\\n倒しても倒しても起き上がってきやがる。","ENG":"Drat! Why wouldn't that stupid robot stay down?","TWN":"該死！那奇怪的機器人為什麼能不斷地站起來？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠가 날 지켜주는 한 우린 무적이야! 그러니 포기하시지!","JPN":"パパが私を守ってくれる限り、私たちは無敵だよ！\\nだから、いい加減観念して！","ENG":"We're invincible so long as Daddy's with us! You'd better give up!","TWN":"只要有爸爸在，我們就是無敵的！快投降吧！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"에잇! 헛소리 집어 치워! 기계면 기계답게 사람에게 복종하라고!","JPN":"ええいっ！　バカ言うな！　機械なら機械らしく\\n人間に服従しろ！","ENG":"Eek! Shut up! You're a machine—act like one!","TWN":"可惡！給我住口！機器還是乖乖服從人類吧！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어머, 우리 예비 사장님께 말투가 그게 뭐죠? 예의 없게시리.","JPN":"あら、未来の社長に向かってそんな口の利き方は\\nないでしょう。礼儀知らずね。","ENG":"You shouldn't talk to our future president like that. That's rude.","TWN":"咦，你怎麼這麼對我們的未來老闆說話？太沒禮貌了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"크윽!","JPN":"くっ！","ENG":"Gah!","TWN":"呃呃！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"조, 좋아! 너도 언더그라운드에서 활동하는 녀석들이니 돈이 필요하겠지?","JPN":"こ、こうしよう！　お前らもアンダーグラウンドで\\n活動してるんだし、金が必要だろ？","ENG":"O-okay! You're from the Underground. You like money, right?","TWN":"對了！你也是在地下世界活動的傢伙，肯定需要錢吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"협상, 협상을 하자!","JPN":"交渉、交渉をしよう！","ENG":"Parley. I invoke the right of parley!","TWN":"我們來談判吧，談判！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"지금 내 편을 들어준다면 저쪽에서 지불한 금액의 두 배, 아니 세 배를 지불하겠어!","JPN":"俺の味方をしてくれたら向こうの2倍、いや3倍をやる！","ENG":"Help me, and I'll pay you twice—no, three times the amount that they paid you.","TWN":"你如果加入到我們這一邊，我就付你兩倍，不，三倍的價錢！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"거 참 흥미로운 제안이네요.","JPN":"実に興味深いご提案ですね。","ENG":"That's an interesting offer.","TWN":"真是一個有趣的提議。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"크큭, 그래. 그렇게 나와야지. 그럼 어서 날 도와서 저것들을......","JPN":"ククッ。そう来なくっちゃ。じゃあ、俺と一緒にあいつらを……","ENG":"Heh heh, yes, that's more like it. Now, help me get rid of—","TWN":"嘿嘿，沒錯，這就對了。快幫我把那些傢伙……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 누가 언더그라운드라는 거죠?","JPN":"でも、誰がアンダーグラウンドで活動してるって？","ENG":"But who's from the Underground?","TWN":"不過你說誰是地下世界的人？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저흰 엄연히 관리국의 정.식.라.이.선.스 를 보유한 팀이라서요.","JPN":"私たちは管理局お墨付きの「ラ・イ・セ・ン・ス」を\\nもらってますからね。","ENG":"We've been OFFICIALLY LICENSED by the Administration.","TWN":"我們擁有管理局的正——式——執——照。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아쉽게도 조건부적합으로 그 제안은 받아들일 수 없겠네요.","JPN":"残念ながら条件を満たしていないので、その提案は\\n受け入れられませんね。","ENG":"I'm sorry, but we can't meet your condition or offer.","TWN":"很遺憾你不符合條件，不能接受你的提議。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이, 이 녀석들이!","JPN":"こ、この野郎！","ENG":"Y-you jerk!","TWN":"你、你們！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"날 가지고 놀아?!","JPN":"俺のことをバカにしてるのか！？","ENG":"How dare you play with me?","TWN":"竟敢耍我？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};